plugin.executeCode:
const t = input.trim();
const lines = [];
const re = /(-?[\d.]+)\s*°?\s*([CcFfKk])\b/g;
let m;
while ((m = re.exec(t)) !== null) {
  const val = parseFloat(m[1]);
  const unit = m[2].toUpperCase();
  let C, F, K;
  if (unit === 'C') { C = val; F = C * 9/5 + 32; K = C + 273.15; }
  else if (unit === 'F') { F = val; C = (F - 32) * 5/9; K = C + 273.15; }
  else if (unit === 'K') { K = val; C = K - 273.15; F = C * 9/5 + 32; }
  lines.push(
    `${val}°${unit}  →  ${C.toFixed(2)}°C  |  ${F.toFixed(2)}°F  |  ${K.toFixed(2)} K`
  );
}
if (lines.length === 0) return { output: '', error: 'No temperature found. Try "100°C" or "32F" or "373.15K".' };
return { output: lines.join('\n'), outputLanguage: 'text' };
